const supabaseUrl = $('settings').first().json.SUPABASE_URL;
const apiKey = $('settings').first().json.SUPABASE_API_KEY;
const headers = { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey, 'Content-Type': 'application/json' };
const trigger = $('workflow_trigger').first().json;
const operation = trigger.operation || 'list_drafts';
let contentId = trigger.content_id || '';
const contentTitle = trigger.content_title || '';
const typeFilter = trigger.content_type_filter || '';
const scheduleDate = trigger.schedule_date || '';

// Title → ID resolution: if content_title is provided but content_id is not, look it up
if (!contentId && contentTitle && ['approve', 'publish', 'reject', 'schedule', 'list_versions', 'get_version', 'save_version'].includes(operation)) {
  let lookupUrl = supabaseUrl + '/rest/v1/published_content?title=eq.' + encodeURIComponent(contentTitle) + '&order=created_at.desc&select=id,title,content_type,genre_slug,status,created_at';
  if (typeFilter) lookupUrl += '&content_type=eq.' + typeFilter;
  const matches = await this.helpers.httpRequest({ method: 'GET', url: lookupUrl, headers });
  if (!Array.isArray(matches) || matches.length === 0) {
    return [{ json: { result: 'Error: No content found with title "' + contentTitle + '". Use list_drafts or list_published to see available titles.', send_notification: false } }];
  } else if (matches.length > 1) {
    const uniqueTypes = [...new Set(matches.map(m => m.content_type))];
    if (uniqueTypes.length > 1) {
      // Different content types — ask which type
      return [{ json: { result: 'NEEDS_CLARIFICATION: Multiple items share that title with different types (' + uniqueTypes.join(', ') + '). Ask the user which content type they mean, then call manage_library again with content_type_filter.', send_notification: false } }];
    } else {
      // Same content type — show list with dates so user can pick by number or date
      const list = matches.map((m, i) => (i+1) + '. ' + m.title + ' (' + m.content_type + ', ' + (m.genre_slug || 'no genre') + ', ' + m.status + ') created ' + new Date(m.created_at || 0).toLocaleDateString() + ' [ID: ' + m.id + ']').join('\n');
      return [{ json: { result: 'NEEDS_CLARIFICATION: Found ' + matches.length + ' ' + uniqueTypes[0] + ' items with that title. Ask the user which one (e.g. "the first one", "the one from today"), then call manage_library again with the correct content_id from this list:\n' + list, send_notification: false } }];
    }
  } else {
    contentId = matches[0].id;
  }
}
let recipientEmail = trigger.recipient_email;
let bccEmail = trigger.bcc_email;
if (!recipientEmail) {
  try {
    const emailRows = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/app_config?key=in.(recipient_email,bcc_email)&select=key,value',
      headers: { 'apikey': apiKey, 'Authorization': 'Bearer ' + apiKey }
    });
    for (const row of emailRows) {
      if (row.key === 'recipient_email') recipientEmail = row.value;
      if (row.key === 'bcc_email') bccEmail = row.value;
    }
  } catch (e) {
    recipientEmail = 'eric@agileadtesting.com';
    bccEmail = '';
  }
}
recipientEmail = recipientEmail || 'eric@agileadtesting.com';
bccEmail = bccEmail || '';

let result = '';
let send_notification = false;
let notification_subject = '';
let notification_body = '';
let content_title = '';

// Helper: save a version snapshot to content_versions
async function saveVersionSnapshot(cId, changedBy, changeNote) {
  // GET current content_text and title
  const contentResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/published_content?id=eq.' + cId + '&select=content_text,title',
    headers
  });
  const contentRow = Array.isArray(contentResp) && contentResp.length > 0 ? contentResp[0] : null;
  if (!contentRow) return null;

  // GET max version_number
  const versionsResp = await this.helpers.httpRequest({
    method: 'GET',
    url: supabaseUrl + '/rest/v1/content_versions?content_id=eq.' + cId + '&order=version_number.desc&limit=1&select=version_number',
    headers
  });
  const maxVersion = Array.isArray(versionsResp) && versionsResp.length > 0 ? versionsResp[0].version_number : 0;
  const newVersion = maxVersion + 1;

  // POST new version
  await this.helpers.httpRequest({
    method: 'POST',
    url: supabaseUrl + '/rest/v1/content_versions',
    headers: { ...headers, 'Prefer': 'return=minimal' },
    body: {
      content_id: cId,
      version_number: newVersion,
      content_text: contentRow.content_text || '',
      changed_by: changedBy,
      change_note: changeNote,
      created_at: new Date().toISOString()
    }
  });
  return { version_number: newVersion, title: contentRow.title };
}

// Helper: build notification HTML
function buildNotification(op, title, newStatus) {
  const now = new Date().toISOString();
  notification_subject = 'Content Library: ' + op.charAt(0).toUpperCase() + op.slice(1) + ' - ' + (title || 'Untitled');
  notification_body = '<h2>Content Library Update</h2>' +
    '<p><strong>Action:</strong> ' + op + '</p>' +
    '<p><strong>Title:</strong> ' + (title || 'Untitled') + '</p>' +
    '<p><strong>New Status:</strong> ' + newStatus + '</p>' +
    '<p><strong>Time:</strong> ' + now + '</p>';
  send_notification = true;
}

if (operation === 'list_drafts' || operation === 'list_published') {
  const status = operation === 'list_drafts' ? 'draft' : 'published';
  let url = supabaseUrl + '/rest/v1/published_content?status=eq.' + status + '&order=created_at.desc&limit=20&select=id,title,content_type,genre_slug,status,created_at,published_at';
  if (typeFilter) url += '&content_type=eq.' + typeFilter;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No ' + status + ' content found.';
  } else {
    result = 'Found ' + items.length + ' ' + status + ' item(s):\n' + items.map((item, i) => 
      (i + 1) + '. ' + item.title + ' (' + item.content_type + ', ' + (item.genre_slug || 'no genre') + ') \u2014 ' + new Date(item.created_at).toLocaleDateString() + ' [ID: ' + item.id + ']'
    ).join('\n');
  }

} else if (operation === 'list_scheduled') {
  let url = supabaseUrl + '/rest/v1/published_content?status=eq.scheduled&order=created_at.desc&limit=20&select=id,title,content_type,genre_slug,status,metadata,created_at';
  if (typeFilter) url += '&content_type=eq.' + typeFilter;
  const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
  const items = Array.isArray(resp) ? resp : [];
  if (items.length === 0) {
    result = 'No scheduled content found.';
  } else {
    result = 'Found ' + items.length + ' scheduled item(s):\n' + items.map((item, i) => {
      const sd = item.metadata && item.metadata.schedule_date ? item.metadata.schedule_date : 'no date';
      return (i + 1) + '. ' + item.title + ' (' + item.content_type + ', ' + (item.genre_slug || 'no genre') + ') \u2014 Scheduled: ' + sd + ' [ID: ' + item.id + ']';
    }).join('\n');
  }

} else if (operation === 'list_versions') {
  if (!contentId) {
    result = 'Error: content_id is required for list_versions operation.';
  } else {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/content_versions?content_id=eq.' + contentId + '&order=version_number.desc&select=version_number,changed_by,change_note,created_at',
      headers
    });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length === 0) {
      result = 'No versions found for content_id: ' + contentId;
    } else {
      result = 'Found ' + items.length + ' version(s):\n' + items.map((v, i) =>
        'v' + v.version_number + ' \u2014 ' + (v.changed_by || 'unknown') + ' \u2014 ' + (v.change_note || 'no note') + ' \u2014 ' + new Date(v.created_at).toLocaleDateString()
      ).join('\n');
    }
  }

} else if (operation === 'get_version') {
  const versionNumber = trigger.version_number;
  if (!contentId || !versionNumber) {
    result = 'Error: content_id and version_number are required for get_version operation.';
  } else {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/content_versions?content_id=eq.' + contentId + '&version_number=eq.' + versionNumber + '&select=version_number,content_text,changed_by,change_note,created_at',
      headers
    });
    const items = Array.isArray(resp) ? resp : [];
    if (items.length === 0) {
      result = 'Version ' + versionNumber + ' not found for content_id: ' + contentId;
    } else {
      const v = items[0];
      result = 'Version ' + v.version_number + ' by ' + (v.changed_by || 'unknown') + ':\n' + (v.content_text || '(empty)');
    }
  }

} else if (operation === 'save_version') {
  if (!contentId) {
    result = 'Error: content_id is required for save_version operation.';
  } else {
    const changedBy = trigger.changed_by || 'system';
    const changeNote = trigger.change_note || 'Manual version snapshot';
    const snapshot = await saveVersionSnapshot.call(this, contentId, changedBy, changeNote);
    if (!snapshot) {
      result = 'Error: content not found for content_id: ' + contentId;
    } else {
      result = 'Version ' + snapshot.version_number + ' saved for "' + snapshot.title + '".';
    }
  }

} else if (operation === 'schedule') {
  if (!contentId || !scheduleDate) {
    result = 'Error: content_id and schedule_date are required for schedule operation.';
  } else {
    // GET existing metadata to merge
    const existing = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/published_content?id=eq.' + contentId + '&select=metadata,title',
      headers
    });
    const row = Array.isArray(existing) && existing.length > 0 ? existing[0] : null;
    if (!row) {
      result = 'Error: content not found for content_id: ' + contentId;
    } else {
      content_title = row.title || 'Untitled';
      const existingMeta = row.metadata && typeof row.metadata === 'object' ? row.metadata : {};
      const mergedMeta = { ...existingMeta, schedule_date: scheduleDate };
      const body = { status: 'scheduled', metadata: mergedMeta, updated_at: new Date().toISOString() };
      await this.helpers.httpRequest({
        method: 'PATCH',
        url: supabaseUrl + '/rest/v1/published_content?id=eq.' + contentId,
        headers: { ...headers, 'Prefer': 'return=representation' },
        body
      });
      result = 'Content "' + content_title + '" scheduled for ' + scheduleDate + '.';
      buildNotification('schedule', content_title, 'scheduled');
    }
  }

} else if (['approve', 'publish', 'reject'].includes(operation)) {
  if (!contentId) {
    result = 'Error: content_id is required for ' + operation + ' operation.';
  } else {
    // Auto-snapshot version before approve/publish
    if (operation === 'approve' || operation === 'publish') {
      const changeNote = 'Auto-snapshot before ' + operation;
      await saveVersionSnapshot.call(this, contentId, 'system', changeNote);
    }

    // Get title for notification
    const titleResp = await this.helpers.httpRequest({
      method: 'GET',
      url: supabaseUrl + '/rest/v1/published_content?id=eq.' + contentId + '&select=title',
      headers
    });
    content_title = Array.isArray(titleResp) && titleResp.length > 0 ? (titleResp[0].title || 'Untitled') : 'Untitled';

    const newStatus = operation === 'approve' ? 'approved' : operation === 'publish' ? 'published' : 'rejected';
    const body = { status: newStatus, updated_at: new Date().toISOString() };
    if (operation === 'publish') body.published_at = new Date().toISOString();
    await this.helpers.httpRequest({ method: 'PATCH', url: supabaseUrl + '/rest/v1/published_content?id=eq.' + contentId, headers: { ...headers, 'Prefer': 'return=representation' }, body });
    result = 'Content "' + content_title + '" ' + (operation === 'approve' ? 'approved' : operation === 'publish' ? 'published' : 'rejected') + ' successfully.';

    buildNotification(operation, content_title, newStatus);
  }

} else {
  result = 'Unknown operation: ' + operation + '. Valid operations: list_drafts, list_published, list_scheduled, list_versions, get_version, save_version, schedule, approve, publish, reject';
}

return [{ json: { result, send_notification, notification_subject, notification_body, recipient_email: recipientEmail, bcc_email: bccEmail } }];
